  "trivia": [
    {
      "id": "2010-africa-first",
      "year": 2010,
      "category": "firsts",
      "fact": "2010 was the first World Cup hosted in Africa. South Africa won the right amid heavy controversy (Sepp Blatter favoured the rotation). Spain became the first European nation ever to win a World Cup outside Europe.",
      "teams": [
        "South Africa",
        "Spain"
      ]
    },
    {
      "id": "2010-iniesta-winner",
      "year": 2010,
      "category": "finals",
      "fact": "Andrés Iniesta scored Spain's only goal of the 2010 final in the 116th minute — Spain 1-0 Netherlands a.e.t., in the dirtiest WC final ever (14 yellow cards + Heitinga red). It was Spain's first World Cup title; they became the first team to win a WC after losing their opening match.",
      "players": [
        "Andrés Iniesta"
      ],
      "teams": [
        "Spain",
        "Netherlands"
      ]
    }
  ],
